SourceCode.Declaration:
/// <summary>
/// Call SQL processing actions
/// </summary>
public class SIMSStartRunActionSQL extends SIMSStartRunAction
{
}

Method.Source:
/// <summary>
/// Method update
/// </summary>
/// <returns>return if this method has errors - reason - we can throw during error or continue processing</returns>
protected boolean update()
{
    SIMSStartTable      startTable  = SIMSStartTable::find(this.parmActionRecId());
    str                 sqlQuery    = startTable.SQL;
    boolean             hasErrorsRet = true;
    int                 rowsAffected;

    rowsAffected = SIMSStartSqlRunner::executeNonQuery(sqlQuery);
    this.parmResultMessage(strFmt("@SIMSStartProcessing:AffectedToTheRows", rowsAffected));
    hasErrorsRet = false;
    return hasErrorsRet;
}
